import numpy as np

# {This algorithm introduces a cooperative and competitive balance by adjusting node selection based on proximity and remaining unvisited nodes, while incorporating a variable risk factor to explore potential gains in efficiency.}
def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        if current_node != depot_node:
            return depot_node
        return None

    # List of nodes not currently targeted by trucks
    available_nodes = [node for node in unvisited_nodes if node not in truck_nodes]

    node_scores = {}

    for node in available_nodes:
        current_to_node = distance_matrix[current_node, node]
        proximity_score = 1.0 / ((current_to_node + 1) if current_to_node > 0 else 1)
        risk_factor = np.random.uniform(0.8, 1.2)  # Variable risk factor

        # Combine factors, encourage proximity with calculated risk
        score = current_to_node * proximity_score * risk_factor
        node_scores[node] = score

    # Choose the node with the smallest score
    next_node = min(node_scores, key=node_scores.get, default=None)

    return next_node

